部分題目需要結合懶刪除堆。

做法不止一種，部分題目也可以用有序集合/權值樹狀陣列等資料結構解決。

**對頂堆**：
- 用一個最大堆存較小的一半，一個最小堆存較大的一半
- 維護兩個堆的大小平衡，即可 $O(1)$ 查詢中位數

```cpp
// 對頂堆求中位數
priority_queue<int> lo;                            // 最大堆（較小的一半）
priority_queue<int, vector<int>, greater<int>> hi; // 最小堆（較大的一半）

void addNum(int num) {
    if (lo.empty() || num <= lo.top()) {
        lo.push(num);
    } else {
        hi.push(num);
    }
    // 平衡：lo 的大小 >= hi 且最多多 1 個
    if (lo.size() > hi.size() + 1) {
        hi.push(lo.top());
        lo.pop();
    } else if (hi.size() > lo.size()) {
        lo.push(hi.top());
        hi.pop();
    }
}

double findMedian() {
    if (lo.size() > hi.size()) {
        return lo.top();
    }
    return (lo.top() + hi.top()) / 2.0;
}
```

