struct UnionFind {
    vector<int> fa, sz;
    int cc;
    explicit UnionFind(int n) : fa(n), sz(n, 1), cc(n) {
        iota(fa.begin(), fa.end(), 0);
    }

    int find(int x) {
        if (fa[x] != x) {
            fa[x] = find(fa[x]); // 路徑壓縮
        }
        return fa[x];
    }

    bool isSame(int x, int y) {
        return find(x) == find(y);
    }

    bool merge(int x, int y) {
        x = find(x);
        y = find(y);
        if (x == y) {
            return false;
        }
        fa[x] = y; // 小的掛到大的下面（啟發式合併）
        sz[y] += sz[x];
        cc -= 1;
        return true;
    }

    int getSize(int x) {
        return sz[find(x)];
    }
};
