**C++ 樹狀陣列 (Fenwick Tree) 模板**：

```cpp
// 樹狀陣列：支援單點修改與字首查詢，O(log n)
struct Fenwick {
    int n;
    vector<long long> tree;

    Fenwick(int n) : n(n), tree(n + 1, 0) {
    }

    int lowbit(int x) {
        return x & -x; // 取最低位的 1
    }

    // 單點修改：將 a[i] 增加 delta
    void update(int i, long long delta) {
        for (; i <= n; i += lowbit(i)) {
            tree[i] += delta; // 向上更新祖先節點
        }
    }

    // 字首查詢：返回 a[1..i] 的和
    long long query(int i) {
        long long sum = 0;
        for (; i > 0; i -= lowbit(i)) {
            sum += tree[i]; // 向下累加字首
        }
        return sum;
    }
};
```

