**C++ 逆序對 (Inversions using Fenwick) 模板**：

```cpp
// 利用樹狀陣列統計逆序對數量
long long countInversions(vector<int>& nums) {
    int n = nums.size();
    vector<int> sorted = nums;
    sort(sorted.begin(), sorted.end());
    sorted.erase(unique(sorted.begin(), sorted.end()), sorted.end()); // 離散化

    Fenwick fenwick(sorted.size());
    long long inversions = 0;

    for (int i = n - 1; i >= 0; --i) {
        int rank = lower_bound(sorted.begin(), sorted.end(), nums[i]) - sorted.begin() + 1;
        inversions += fenwick.query(rank - 1);
        fenwick.update(rank, 1);
    }

    return inversions;
}
```

