**C++ 線段樹 (Segment Tree - Point Update) 模板**：

```cpp
// 線段樹：支援單點修改與區間查詢
struct SegmentTree {
    int n;
    vector<int> tree;

    SegmentTree(int n) : n(n), tree(4 * n, 0) {
    }

    void update(int node, int start, int end, int idx, int val) {
        if (start == end) {
            tree[node] = val;
            return;
        }
        int mid = start + (end - start) / 2;
        if (idx <= mid) {
            update(2 * node, start, mid, idx, val);
        } else {
            update(2 * node + 1, mid + 1, end, idx, val);
        }

        tree[node] = max(tree[2 * node], tree[2 * node + 1]); // 向上合併子區間
    }

    int query(int node, int start, int end, int l, int r) {
        if (r < start || end < l) {
            return 0;
        }
        if (l <= start && end <= r) {
            return tree[node];
        }

        int mid = start + (end - start) / 2;
        int p1 = query(2 * node, start, mid, l, r);
        int p2 = query(2 * node + 1, mid + 1, end, l, r);
        return max(p1, p2);
    }
};
```

把任意區間用 $O(\log n)$ 個區間表示，線段樹的每個節點記錄對應區間的資訊。
- **詢問**：把詢問區間拆分成 $O(\log n)$ 個區間，對應著線段樹的 $O(\log n)$ 個節點，把這 $O(\log n)$ 個節點的資訊合併，即為答案。
- **區間更新**：仍然是拆分成 $O(\log n)$ 個區間，對應著線段樹的 $O(\log n)$ 個節點。但對於其中的非葉節點，不把更新的內容往下傳遞給子節點，而是記錄「發生了更新，內容為 xxx」，把更新的內容記錄下來。直到後續的詢問或更新操作，需要訪問或修改更下面的子節點資訊時，才把更新的內容往下傳。

基礎模板程式碼如下。為方便入門理解，我沒有做複雜封裝。通用模板程式碼可以參考 AtCoder Library 的 [lazysegtree.hpp](/link/?target=https%3A%2F%2Fgithub.com%2Fatcoder%2Fac-library%2Fblob%2Fmaster%2Fatcoder%2Flazysegtree.hpp)。

**C++ Lazy 線段樹 (Segment Tree - Range Update) 模板**：

```cpp
// Lazy 線段樹：支援區間修改與區間查詢，O(log n)
// 使用懶標記（Lazy Propagation）延遲更新，提高區間修改效率
struct LazySegmentTree {
    int n;                      // n: 陣列大小
    vector<long long> tree;     // tree[i]: 節點 i 表示的區間和
    vector<long long> lazy;     // lazy[i]: 節點 i 的懶標記（待傳遞的增量）

    // 初始化：建立大小為 4n 的線段樹（完全二叉樹需要 4n 空間）
    LazySegmentTree(int n) : n(n), tree(4 * n, 0), lazy(4 * n, 0) {
    }

    // 下推懶標記：將節點 node 的懶標記應用到當前區間，並傳遞給子節點
    // node: 當前節點編號，[start, end]: 當前節點表示的區間
    void push(int node, int start, int end) {
        if (lazy[node] != 0) {
            // 將懶標記應用到當前區間：區間長度 × 增量
            tree[node] += lazy[node] * (end - start + 1);

            if (start != end) {
                // 非葉子節點：將懶標記傳遞給左右子節點
                lazy[2 * node] += lazy[node];       // 左子節點
                lazy[2 * node + 1] += lazy[node];   // 右子節點
            }
            lazy[node] = 0; // 清除當前節點的懶標記
        }
    }

    // 區間更新：將區間 [l, r] 的所有元素增加 val
    // node: 當前節點，[start, end]: 當前節點表示的區間，[l, r]: 要更新的目標區間
    void updateRange(int node, int start, int end, int l, int r, long long val) {
        push(node, start, end); // 先下推懶標記

        // 無交集：當前區間與目標區間無重疊
        if (start > end || start > r || end < l) {
            return;
        }

        // 完全包含：當前區間完全在目標區間內
        if (start >= l && end <= r) {
            lazy[node] += val;      // 添加懶標記
            push(node, start, end); // 立即應用到當前節點
            return;
        }

        // 部分重疊：遞迴處理左右子樹
        int mid = start + (end - start) / 2;
        updateRange(2 * node, start, mid, l, r, val);           // 更新左子樹
        updateRange(2 * node + 1, mid + 1, end, l, r, val);     // 更新右子樹
        tree[node] = tree[2 * node] + tree[2 * node + 1];       // 合併子節點結果
    }

    // 區間查詢：查詢區間 [l, r] 的和
    // node: 當前節點，[start, end]: 當前節點表示的區間，[l, r]: 查詢的目標區間
    long long queryRange(int node, int start, int end, int l, int r) {
        // 無交集：當前區間與目標區間無重疊
        if (start > end || start > r || end < l) {
            return 0;
        }

        push(node, start, end); // 先下推懶標記，確保資料最新

        // 完全包含：當前區間完全在目標區間內
        if (start >= l && end <= r) {
            return tree[node];
        }

        // 部分重疊：遞迴查詢左右子樹並合併結果
        int mid = start + (end - start) / 2;
        long long p1 = queryRange(2 * node, start, mid, l, r);      // 左子樹結果
        long long p2 = queryRange(2 * node + 1, mid + 1, end, l, r); // 右子樹結果
        return p1 + p2;
    }
};
```

