**C++ 動態開點線段樹 (Dynamic Segment Tree) 模板**：

```cpp
// 動態開點線段樹：按需建立節點，適用於值域大的場景
struct DynamicSegNode {
    long long val, lazy;
    DynamicSegNode *left, *right;
    DynamicSegNode()
        : val(0), lazy(0), left(nullptr), right(nullptr) { // 初始為空節點
    }
};

struct DynamicSegTree {
    DynamicSegNode* root;
    long long left_bound, right_bound;

    DynamicSegTree(long long l, long long r)
        : root(new DynamicSegNode()), left_bound(l), right_bound(r) {
    }

    void push(DynamicSegNode* node, long long start, long long end) {
        if (!node->left) {
            node->left = new DynamicSegNode();
        }
        if (!node->right) {
            node->right = new DynamicSegNode();
        }
        if (node->lazy != 0) {
            long long mid = start + (end - start) / 2;
            node->left->val += node->lazy * (mid - start + 1);
            node->left->lazy += node->lazy;
            node->right->val += node->lazy * (end - mid);
            node->right->lazy += node->lazy;
            node->lazy = 0;
        }
    }

    void update(DynamicSegNode* node, long long start, long long end, long long l, long long r,
                long long val) {
        if (l <= start && end <= r) {
            node->val += val * (end - start + 1);
            node->lazy += val;
            return;
        }
        push(node, start, end);
        long long mid = start + (end - start) / 2;
        if (l <= mid) {
            update(node->left, start, mid, l, r, val);
        }
        if (r > mid) {
            update(node->right, mid + 1, end, l, r, val);
        }
        node->val = node->left->val + node->right->val;
    }

    long long query(DynamicSegNode* node, long long start, long long end, long long l,
                    long long r) {
        if (l <= start && end <= r) {
            return node->val;
        }
        push(node, start, end);
        long long mid = start + (end - start) / 2;
        long long res = 0;
        if (l <= mid) {
            res += query(node->left, start, mid, l, r);
        }
        if (r > mid) {
            res += query(node->right, mid + 1, end, l, r);
        }
        return res;
    }
};
```

**C++ 可持久化線段樹 (Persistent Segment Tree / Chairman Tree) 模板**：

```cpp
// 可持久化線段樹（主席樹）：保留歷史版本，支援查詢區間第 k 小
// 核心思想：每次修改只複製路徑上的節點，其他節點共享
struct PresidentNode {
    int count;      // 當前區間內的元素個數
    int left, right; // 左右子節點的索引
};

struct PresidentTree {
    vector<PresidentNode> tree; // 存儲所有節點（包括歷史版本）
    vector<int> roots;          // 每個版本的根節點索引
    int n;                      // 值域範圍 [1, n]

    // 初始化：n 為值域大小，q 為操作次數
    PresidentTree(int n, int q) : n(n) {
        tree.push_back({0, 0, 0}); // 空節點作為哨兵（索引 0）
        roots.reserve(q + 1);
        roots.push_back(0);        // 版本 0 為空樹
    }

    // 複製節點：創建一個新節點作為舊節點的副本
    int clone(int node) {
        tree.push_back(tree[node]);
        return tree.size() - 1;
    }

    // 單點更新：在 prev_node 基礎上插入值 val，返回新樹的根節點
    // [start, end] 為當前節點表示的值域範圍
    int update(int prev_node, int start, int end, int val) {
        int curr_node = clone(prev_node); // 複製當前節點
        tree[curr_node].count++;           // 增加計數

        if (start == end) {
            return curr_node; // 葉子節點，返回
        }

        int mid = start + (end - start) / 2;
        if (val <= mid) {
            // 值在左半區間，更新左子樹
            tree[curr_node].left = update(tree[prev_node].left, start, mid, val);
        } else {
            // 值在右半區間，更新右子樹
            tree[curr_node].right = update(tree[prev_node].right, mid + 1, end, val);
        }
        return curr_node;
    }

    // 插入值：創建新版本
    void insert(int val) {
        roots.push_back(update(roots.back(), 1, n, val));
    }

    // 查詢區間第 k 小：在版本 [left_root, right_root] 之間
    // 返回第 k 小的值（1-indexed）
    int queryKth(int left_root, int right_root, int start, int end, int k) {
        if (start == end) {
            return start; // 找到第 k 小的值
        }

        // 計算左子樹在 [left_root, right_root] 區間內的元素個數
        int count = tree[tree[right_root].left].count - tree[tree[left_root].left].count;
        int mid = start + (end - start) / 2;

        if (count >= k) {
            // 第 k 小在左子樹
            return queryKth(tree[left_root].left, tree[right_root].left, start, mid, k);
        }
        // 第 k 小在右子樹
        return queryKth(tree[left_root].right, tree[right_root].right, mid + 1, end, k - count);
    }
};
```

[ST 表](/link/?target=https%3A%2F%2Foi-wiki.org%2Fds%2Fsparse-table%2F) 支援區間最值查詢（Range Minimum/Maximum Query，RMQ），但不支援修改。

優點是程式碼短，且查詢的時間複雜度是 $O(1)$。所以作為補充內容，附在此處。

**C++ ST 表 (Sparse Table for RMQ) 模板**：

```cpp
// ST 表：O(n log n) 預處理，O(1) 查詢區間最值
// 適用於靜態區間最值查詢（不支援修改）
struct SparseTable {
    vector<vector<int>> st;  // st[i][j] 表示從 i 開始，長度為 2^j 的區間的最小值
    vector<int> log2;        // log2[i] = floor(log2(i))，預處理加速查詢

    // 構造函數：預處理 ST 表
    SparseTable(const vector<int>& arr) {
        int n = arr.size();
        int max_log = log2Floor(n) + 1; // 需要的最大 log 層數
        st.assign(n, vector<int>(max_log));
        log2.assign(n + 1, 0);

        // 預處理 log2 值
        for (int i = 2; i <= n; i++) {
            log2[i] = log2[i / 2] + 1;
        }

        // 初始化：長度為 1 的區間（2^0 = 1）
        for (int i = 0; i < n; i++) {
            st[i][0] = arr[i];
        }

        // 動態規劃：從小區間合併到大區間
        for (int j = 1; j < max_log; j++) {
            for (int i = 0; i + (1 << j) <= n; i++) {
                // st[i][j] = min(左半部分, 右半部分)
                // 左半：st[i][j-1]，右半：st[i + 2^(j-1)][j-1]
                st[i][j] = min(st[i][j - 1], st[i + (1 << (j - 1))][j - 1]);
            }
        }
    }

    // 計算 floor(log2(n))
    int log2Floor(int n) {
        return 31 - __builtin_clz(n); // 前導零個數
    }

    // 查詢區間 [left, right] 的最小值，O(1) 時間
    int query(int left, int right) {
        int j = log2[right - left + 1]; // 找到最大的 j 使得 2^j <= 區間長度
        // 用兩個長度為 2^j 的區間覆蓋 [left, right]
        // 左段：[left, left + 2^j - 1]
        // 右段：[right - 2^j + 1, right]
        // 兩段可能重疊，但 min 操作滿足可重複貢獻性質
        return min(st[left][j], st[right - (1 << j) + 1][j]);
    }
};
```

**C++ 伸展樹 (Splay Tree) 模板**：

```cpp
// Splay 樹：自調整二叉搜索樹
struct SplayNode {
    int val, size, count;
    SplayNode *p, *ch[2];
    SplayNode(int v)
        : val(v), size(1), count(1), p(nullptr) { // 單一節點
        ch[0] = ch[1] = nullptr;
    }
};

struct SplayTree {
    SplayNode* root;
    SplayTree() : root(nullptr) {
    }

    void maintain(SplayNode* x) {
        if (x) {
            x->size = x->count;
            if (x->ch[0]) {
                x->size += x->ch[0]->size;
            }
            if (x->ch[1]) {
                x->size += x->ch[1]->size;
            }
        }
    }

    void rotate(SplayNode* x) {
        SplayNode* y = x->p;
        SplayNode* z = y->p;
        int k = (y->ch[1] == x);
        y->ch[k] = x->ch[k ^ 1];
        if (x->ch[k ^ 1]) {
            x->ch[k ^ 1]->p = y;
        }
        x->ch[k ^ 1] = y;
        y->p = x;
        x->p = z;
        if (z) {
            z->ch[z->ch[1] == y] = x;
        }
        maintain(y);
        maintain(x);
    }

    void splay(SplayNode* x) {
        for (SplayNode* f = x->p; f = x->p, f; rotate(x)) {
            if (f->p) {
                rotate((x == f->ch[1]) == (f == f->p->ch[1]) ? f : x);
            }
        }
        root = x;
    }
};
```

**根號分解核心思想**：
- 將長度為 $n$ 的序列分成約 $\sqrt{n}$ 個塊，每塊大小約為 $\sqrt{n}$。
- 對於區間查詢：中間的完整塊直接使用預處理資料，兩端的零散部分暴力掃描。
- 單次查詢時間複雜度為 $O(\sqrt{n})$。

**C++ 根號分解 (Sqrt Decomposition / 分塊) 模板**：

```cpp
// 根號分解：將陣列分塊，支援 O(sqrt(n)) 的區間查詢與修改
// 空間複雜度 O(n)，預處理 O(n)，單次操作 O(sqrt(n))
struct SqrtDecomposition {
    int n, block_size;        // n: 陣列長度, block_size: 每塊大小 (sqrt(n))
    vector<int> arr;          // 原始陣列
    vector<int> block_sum;    // block_sum[i]: 第 i 塊的元素和

    // 構造函數：初始化分塊結構
    SqrtDecomposition(const vector<int>& a) {
        arr = a;
        n = arr.size();
        block_size = max(1, (int)sqrt(n)); // 每塊大小 sqrt(n)
        int blocks = (n + block_size - 1) / block_size; // 總塊數（向上取整）
        block_sum.assign(blocks, 0);

        // 預處理：計算每個塊的和
        for (int i = 0; i < n; i++) {
            block_sum[i / block_size] += arr[i];
        }
    }

    // 單點修改：將 arr[idx] 更新為 val，O(1)
    void update(int idx, int val) {
        int b_idx = idx / block_size;       // idx 所在的塊編號
        block_sum[b_idx] += val - arr[idx]; // 更新塊和（差值）
        arr[idx] = val;                     // 更新元素值
    }

    // 區間查詢：查詢 [l, r] 的和，O(sqrt(n))
    int query(int l, int r) {
        int sum = 0;
        int b_l = l / block_size;  // 左端點所在塊
        int b_r = r / block_size;  // 右端點所在塊

        if (b_l == b_r) {
            // 區間在同一塊內：直接暴力累加
            for (int i = l; i <= r; i++) {
                sum += arr[i];
            }
        } else {
            // 區間跨多個塊：分三部分處理

            // 1. 左端零散部分：從 l 到當前塊末尾
            for (int i = l, end = (b_l + 1) * block_size - 1; i <= end; i++) {
                sum += arr[i];
            }

            // 2. 中間完整塊：直接使用預處理的塊和
            for (int i = b_l + 1; i < b_r; i++) {
                sum += block_sum[i];
            }

            // 3. 右端零散部分：從最後一塊開頭到 r
            for (int i = b_r * block_size; i <= r; i++) {
                sum += arr[i];
            }
        }
        return sum;
    }
};
```

屬於離線演算法的一種。

